(()=>{"use strict";const csv=e=>{const q=s=>({begin:/"/,end:/"/,beginScope:"quote",endScope:"quote",contains:[{scope:s,match:/""|[^"\r\n]+/}]});const sep=/[\t,]/;const val=/[^,\t\r\n]+/;const num=/(^|[\t,])\s*-?(?:\d+(?:\.\d+)?|\.\d+)(?=[\t,]|$)/;const lit=/(^|[\t,])\s*(?:true|false|null)(?=[\t,]|$)/i;const header={begin:/^/,end:/\r?\n|$/,contains:[q("title"),{scope:"title",match:val},{scope:"punctuation",match:sep}],starts:{contains:[{begin:/(?=.)/,end:/$/,contains:[q("string"),{scope:"number",match:num},{scope:"literal",match:lit},{scope:"attr",match:val},{scope:"punctuation",match:sep}]}]}};return{name:"CSV",aliases:["comma-separated-values","tsv","tab-separated-values"],contains:[header]}};if(typeof hljs!=="undefined"&&hljs&&typeof hljs.registerLanguage==="function"){hljs.registerLanguage("csv",csv);hljs.registerLanguage("tsv",csv)}})();